using System.Text;using Asp.Versioning;using Fixar.API.Security;using Fixar.Application.Common.Models;using Fixar.Domain.Entities;using Fixar.Infrastructure.Identity;using Fixar.Infrastructure.Persistence;using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;
namespace Fixar.API.Controllers;
[ApiController,ApiVersion("1.0"),Route("api/v{version:apiVersion}/customer-cheques"),Authorize(Policy=AuthorizationPolicies.CanViewChequePortfolio)]
public class CustomerChequesController(ApplicationDbContext db):ControllerBase
{
 [HttpGet]public async Task<IActionResult>List(Guid? customerId,string? status,string? currency,DateTime? dueFrom,DateTime? dueTo,bool overdueOnly,int? dueSoonDays,string? bankName,string? search,CancellationToken ct){var q=db.CustomerCheques.AsNoTracking().AsQueryable();if(customerId.HasValue)q=q.Where(x=>x.CustomerId==customerId);if(!string.IsNullOrWhiteSpace(status))q=q.Where(x=>x.Status==status);if(!string.IsNullOrWhiteSpace(currency))q=q.Where(x=>x.Currency==currency.ToUpper());if(dueFrom.HasValue)q=q.Where(x=>x.DueDate>=dueFrom);if(dueTo.HasValue)q=q.Where(x=>x.DueDate<=dueTo);if(overdueOnly)q=q.Where(x=>x.DueDate<DateTime.UtcNow.Date&&x.Status!="Collected");if(dueSoonDays.HasValue)q=q.Where(x=>x.DueDate>=DateTime.UtcNow.Date&&x.DueDate<=DateTime.UtcNow.Date.AddDays(dueSoonDays.Value));if(!string.IsNullOrWhiteSpace(bankName))q=q.Where(x=>x.BankName==bankName);if(!string.IsNullOrWhiteSpace(search)){var s=search.ToLower();q=q.Where(x=>x.PortfolioNumber.ToLower().Contains(s)||x.ChequeNumber.ToLower().Contains(s)||x.Customer.Name.ToLower().Contains(s)||x.DrawerName.ToLower().Contains(s));}var rows=await q.OrderBy(x=>x.DueDate).Select(x=>new CustomerChequeListDto(x.Id,x.PortfolioNumber,x.ChequeNumber,x.CustomerId,x.Customer.CustomerCode,x.Customer.CompanyName??x.Customer.Name,x.CustomerCollectionId,x.BankName,x.DrawerName,x.ReceivedDate,x.DueDate,x.Currency,x.Amount,x.Status,x.FinancialAccountId,x.IsReversed)).ToListAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(rows));}
 [HttpGet("{id:guid}")]public async Task<IActionResult>Detail(Guid id,CancellationToken ct){var x=await db.CustomerCheques.AsNoTracking().Where(x=>x.Id==id).Select(x=>new{x.Id,x.PortfolioNumber,x.ChequeNumber,x.CustomerId,CustomerName=x.Customer.CompanyName??x.Customer.Name,x.CustomerCollectionId,x.BankName,x.BankBranch,x.AccountHolder,x.DrawerName,x.ChequeDate,x.DueDate,x.Currency,x.Amount,x.Status,x.ReceivedDate,x.DepositedDate,x.CollectedDate,x.ReturnedDate,x.BouncedDate,x.FinancialAccountId,x.BankReference,x.Notes,x.IsReversed,x.ReversedAt,x.ReversalReason}).FirstOrDefaultAsync(ct);return x is null?NotFound(ApiResponse<object>.Fail("Çek portföyde bulunmuyor.","CHEQUE_NOT_FOUND")):Ok(ApiResponse<object>.SuccessResponse(x));}
 [HttpGet("{id:guid}/timeline")]public async Task<IActionResult>Timeline(Guid id,CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await db.ChequeEvents.AsNoTracking().Where(x=>x.CustomerChequeId==id).OrderBy(x=>x.EventDate).Select(x=>new ChequeEventDto(x.Id,x.EventType,x.EventDate,x.PreviousStatus,x.NewStatus,x.FinancialAccountId,x.FinancialTransactionId,x.ReferenceNumber,x.Notes,x.Reason)).ToListAsync(ct)));
 [HttpPost,Authorize(Policy=AuthorizationPolicies.CanManageChequePortfolio),Idempotent]public async Task<IActionResult>Create(ChequeRequest r,CancellationToken ct){var error=await Validate(r,ct);if(error!=null)return BadRequest(ApiResponse<object>.Fail(error,"VALIDATION_ERROR"));await using var tx=await db.Database.BeginTransactionAsync(ct);var x=await New(r,"Draft",ct);Event(x,"Created",null,"Draft",null,null,null);CustomerFinanceSupport.Audit(db,this,"Customer Cheque Created",x.Id,r);await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.PortfolioNumber,x.Status}));}
 [HttpPut("{id:guid}"),Authorize(Policy=AuthorizationPolicies.CanManageChequePortfolio)]public async Task<IActionResult>Update(Guid id,ChequeRequest r,CancellationToken ct){var x=await db.CustomerCheques.FindAsync([id],ct);if(x is null)return NotFound();if(x.Status!="Draft")return Conflict(ApiResponse<object>.Fail("Yalnız taslak çek düzenlenebilir.","CHEQUE_LOCKED"));var error=await Validate(r,ct);if(error!=null)return BadRequest(ApiResponse<object>.Fail(error,"VALIDATION_ERROR"));Apply(x,r);Event(x,"Updated","Draft","Draft",null,null,null);await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id}));}
 [HttpPost("{id:guid}/receive"),Authorize(Policy=AuthorizationPolicies.CanManageChequePortfolio),Idempotent]public Task<IActionResult>Receive(Guid id,ChequeActionRequest r,CancellationToken ct)=>Change(id,"Draft","InPortfolio","Received",r,null,false,ct);
 [HttpPost("{id:guid}/deposit"),Authorize(Policy=AuthorizationPolicies.CanManageChequePortfolio),Idempotent]public Task<IActionResult>Deposit(Guid id,ChequeActionRequest r,CancellationToken ct)=>Change(id,"InPortfolio","DepositedToBank","Deposited",r,"Bank",false,ct);
 [HttpPost("{id:guid}/collect"),Authorize(Policy=AuthorizationPolicies.CanCollectCheque),Idempotent]public async Task<IActionResult>Collect(Guid id,ChequeActionRequest r,CancellationToken ct){await using var tx=await db.Database.BeginTransactionAsync(ct);var x=await db.CustomerCheques.FirstOrDefaultAsync(x=>x.Id==id,ct);if(x is null)return NotFound(ApiResponse<object>.Fail("Çek portföyde bulunmuyor.","CHEQUE_NOT_FOUND"));if(x.Status=="Collected")return Conflict(ApiResponse<object>.Fail("Bu çek daha önce tahsil edilmiş.","ALREADY_COLLECTED"));if(x.Status is not("InPortfolio" or "DepositedToBank"))return Conflict(ApiResponse<object>.Fail("Çek tahsilata uygun durumda değil.","INVALID_STATUS"));var account=await Account(r.FinancialAccountId,x.Currency,null,ct);if(account.Error!=null)return account.Error;var previous=x.Status;var ft=await Finance(account.Value!,x,"Inflow","ChequeCollection","Cheque",x.Id,r,ct);x.Status="Collected";x.CollectedDate=DateTime.UtcNow;x.FinancialAccountId=account.Value!.Id;Event(x,"Collected",previous,x.Status,account.Value.Id,ft.Id,r);CustomerFinanceSupport.Audit(db,this,"Customer Cheque Collected",x.Id,r);await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status,FinancialTransactionId=ft.Id}));}
 [HttpPost("{id:guid}/return"),Authorize(Policy=AuthorizationPolicies.CanManageChequePortfolio),Idempotent]public Task<IActionResult>Return(Guid id,ChequeActionRequest r,CancellationToken ct)=>Change(id,"DepositedToBank","Returned","Returned",r,null,true,ct);
 [HttpPost("{id:guid}/bounce"),Authorize(Policy=AuthorizationPolicies.CanBounceCheque),Idempotent]public async Task<IActionResult>Bounce(Guid id,ChequeActionRequest r,CancellationToken ct){if(string.IsNullOrWhiteSpace(r.Reason))return BadRequest(ApiResponse<object>.Fail("Karşılıksız çek için gerekçe zorunludur.","VALIDATION_ERROR"));await using var tx=await db.Database.BeginTransactionAsync(ct);var x=await db.CustomerCheques.FirstOrDefaultAsync(x=>x.Id==id,ct);if(x is null)return NotFound();if(x.Status!="DepositedToBank")return Conflict(ApiResponse<object>.Fail("Yalnız bankaya verilen çek karşılıksız işaretlenebilir.","INVALID_STATUS"));if(await db.CustomerLedgerEntries.AnyAsync(l=>l.SourceType=="ChequeBounce"&&l.SourceId==x.Id,ct))return Conflict(ApiResponse<object>.Fail("Bu çek için cari borç daha önce yeniden açılmış.","BOUNCE_EXISTS"));var previous=x.Status;x.Status="Bounced";x.BouncedDate=DateTime.UtcNow;db.CustomerLedgerEntries.Add(new CustomerLedgerEntry{Id=Guid.NewGuid(),EntryNumber=await CustomerFinanceSupport.NextNumber(db,"LED",DateTime.UtcNow,ct),CustomerId=x.CustomerId,TransactionDate=DateTime.UtcNow,EntryType="Debit",SourceType="ChequeBounce",SourceId=x.Id,ReferenceNumber=x.PortfolioNumber,Currency=x.Currency,DebitAmount=x.Amount,Description=$"Karşılıksız çek: {r.Reason}",Created=DateTime.UtcNow});Event(x,"Bounced",previous,x.Status,null,null,r);CustomerFinanceSupport.Audit(db,this,"Customer Cheque Bounced",x.Id,r);await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status,FinanceWarning="Müşteri borcu çek tutarı kadar yeniden açıldı."}));}
 [HttpPost("{id:guid}/cancel"),Authorize(Policy=AuthorizationPolicies.CanManageChequePortfolio),Idempotent]public async Task<IActionResult>Cancel(Guid id,ChequeActionRequest r,CancellationToken ct){var x=await db.CustomerCheques.FirstOrDefaultAsync(x=>x.Id==id,ct);if(x is null)return NotFound();if(x.Status is not("Draft" or "InPortfolio"))return Conflict(ApiResponse<object>.Fail("Bu çek bankaya verildiği için doğrudan iptal edilemez.","INVALID_STATUS"));if(x.CustomerCollectionId.HasValue&&await db.CustomerCollections.AnyAsync(c=>c.Id==x.CustomerCollectionId&&c.Status!="Draft"&&c.Status!="Cancelled",ct))return Conflict(ApiResponse<object>.Fail("Bağlı tahsilat kaydedildiği için çek doğrudan iptal edilemez.","POSTED_COLLECTION"));var previous=x.Status;x.Status="Cancelled";Event(x,"Cancelled",previous,x.Status,null,null,r);CustomerFinanceSupport.Audit(db,this,"Customer Cheque Cancelled",x.Id,r);await db.SaveChangesAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status}));}
 [HttpPost("{id:guid}/reverse-collection"),Authorize(Policy=AuthorizationPolicies.CanCollectCheque),Idempotent]public async Task<IActionResult>ReverseCollection(Guid id,ChequeActionRequest r,CancellationToken ct){if(string.IsNullOrWhiteSpace(r.Reason))return BadRequest(ApiResponse<object>.Fail("Geri alma gerekçesi zorunludur.","VALIDATION_ERROR"));await using var tx=await db.Database.BeginTransactionAsync(ct);var x=await db.CustomerCheques.FirstOrDefaultAsync(x=>x.Id==id,ct);if(x is null)return NotFound();if(x.Status!="Collected")return Conflict(ApiResponse<object>.Fail("Yalnız tahsil edilmiş çek geri alınabilir.","INVALID_STATUS"));var original=await db.FinancialTransactions.Include(t=>t.FinancialAccount).FirstOrDefaultAsync(t=>t.ChequeId==x.Id&&!t.IsReversed&&t.TransactionType=="ChequeCollection",ct);if(original is null)return Conflict(ApiResponse<object>.Fail("Çek tahsilat hareketi bulunamadı.","TRANSACTION_NOT_FOUND"));var reverse=await Finance(original.FinancialAccount,x,"Outflow","Reversal","Reversal",original.Id,r,ct);original.IsReversed=true;original.ReversalTransactionId=reverse.Id;original.ReversedAt=DateTime.UtcNow;original.ReversalReason=r.Reason;var previous=x.Status;x.Status=x.DepositedDate.HasValue?"DepositedToBank":"InPortfolio";x.CollectedDate=null;Event(x,"Reversed",previous,x.Status,original.FinancialAccountId,reverse.Id,r);CustomerFinanceSupport.Audit(db,this,"Cheque Collection Reversed",x.Id,r);await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status,ReversalTransactionId=reverse.Id}));}
 [HttpGet("summary")]public async Task<IActionResult>Summary(CancellationToken ct){var today=DateTime.UtcNow.Date;var rows=await db.CustomerCheques.AsNoTracking().GroupBy(x=>x.Currency).Select(g=>new{Currency=g.Key,InPortfolio=g.Where(x=>x.Status=="InPortfolio").Sum(x=>(decimal?)x.Amount)??0,Deposited=g.Where(x=>x.Status=="DepositedToBank").Sum(x=>(decimal?)x.Amount)??0,Collected=g.Where(x=>x.Status=="Collected").Sum(x=>(decimal?)x.Amount)??0,Overdue=g.Where(x=>x.DueDate<today&&x.Status!="Collected"&&x.Status!="Cancelled").Sum(x=>(decimal?)x.Amount)??0,DueIn7Days=g.Where(x=>x.DueDate>=today&&x.DueDate<=today.AddDays(7)&&x.Status!="Collected").Sum(x=>(decimal?)x.Amount)??0,Bounced=g.Where(x=>x.Status=="Bounced").Sum(x=>(decimal?)x.Amount)??0}).ToListAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(rows));}
 [HttpGet("maturity-calendar")]public async Task<IActionResult>Maturity(CancellationToken ct){var today=DateTime.UtcNow.Date;var rows=await db.CustomerCheques.AsNoTracking().Where(x=>x.Status=="InPortfolio"||x.Status=="DepositedToBank").OrderBy(x=>x.DueDate).Select(x=>new{x.Id,x.PortfolioNumber,CustomerName=x.Customer.CompanyName??x.Customer.Name,x.DueDate,x.Currency,x.Amount,x.Status,Bucket=x.DueDate<today?"Overdue":x.DueDate==today?"Today":x.DueDate<=today.AddDays(7)?"Next7Days":x.DueDate<=today.AddDays(30)?"Next30Days":x.DueDate<=today.AddDays(60)?"Next60Days":"Later"}).ToListAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(rows));}
 [HttpGet("export.csv")]public async Task<IActionResult>Export(CancellationToken ct){var rows=await db.CustomerCheques.AsNoTracking().OrderBy(x=>x.DueDate).Select(x=>new{x.PortfolioNumber,x.ChequeNumber,Customer=x.Customer.CompanyName??x.Customer.Name,x.BankName,x.DrawerName,x.ReceivedDate,x.DueDate,x.Amount,x.Currency,x.Status}).ToListAsync(ct);var sb=new StringBuilder("\uFEFFPortföy No;Çek No;Müşteri;Banka;Keşideci;Alınma;Vade;Tutar;Para Birimi;Durum\n");foreach(var x in rows)sb.AppendLine($"{x.PortfolioNumber};{x.ChequeNumber};{x.Customer};{x.BankName};{x.DrawerName};{x.ReceivedDate:dd.MM.yyyy};{x.DueDate:dd.MM.yyyy};{x.Amount};{x.Currency};{x.Status}");CustomerFinanceSupport.Audit(db,this,"Cheque Portfolio Exported",Guid.Empty,new{});await db.SaveChangesAsync(ct);return File(Encoding.UTF8.GetBytes(sb.ToString()),"text/csv; charset=utf-8","cek-portfoyu.csv");}
 async Task<IActionResult>Change(Guid id,string required,string next,string eventType,ChequeActionRequest r,string? requiredType,bool reason,CancellationToken ct){if(reason&&string.IsNullOrWhiteSpace(r.Reason))return BadRequest(ApiResponse<object>.Fail("Gerekçe zorunludur.","VALIDATION_ERROR"));await using var tx=await db.Database.BeginTransactionAsync(ct);var x=await db.CustomerCheques.FirstOrDefaultAsync(x=>x.Id==id,ct);if(x is null)return NotFound();if(x.Status!=required)return Conflict(ApiResponse<object>.Fail("Çek bu işlem için uygun durumda değil.","INVALID_STATUS"));FinancialAccount? account=null;if(requiredType!=null){var found=await Account(r.FinancialAccountId,x.Currency,requiredType,ct);if(found.Error!=null)return found.Error;account=found.Value;}var previous=x.Status;x.Status=next;if(next=="DepositedToBank"){x.DepositedDate=DateTime.UtcNow;x.FinancialAccountId=account!.Id;}if(next=="Returned")x.ReturnedDate=DateTime.UtcNow;if(next=="InPortfolio")x.ReceivedDate=DateTime.UtcNow;Event(x,eventType,previous,next,account?.Id,null,r);CustomerFinanceSupport.Audit(db,this,$"Customer Cheque {eventType}",x.Id,r);await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(new{x.Id,x.Status}));}
 async Task<(FinancialAccount? Value,IActionResult? Error)>Account(Guid? id,string currency,string? type,CancellationToken ct){if(!id.HasValue)return(null,BadRequest(ApiResponse<object>.Fail("Çek tahsilatı için banka veya kasa hesabı seçilmelidir.","ACCOUNT_REQUIRED")));var a=await db.FinancialAccounts.FirstOrDefaultAsync(x=>x.Id==id,ct);if(a is null)return(null,NotFound(ApiResponse<object>.Fail("Finans hesabı bulunamadı.","ACCOUNT_NOT_FOUND")));if(!a.IsActive)return(null,Conflict(ApiResponse<object>.Fail("Finans hesabı aktif değil.","ACCOUNT_INACTIVE")));if(a.Currency!=currency)return(null,Conflict(ApiResponse<object>.Fail("Finans hesabının para birimi tahsilat ile eşleşmiyor.","CURRENCY_MISMATCH")));if(type!=null&&a.AccountType!=type)return(null,Conflict(ApiResponse<object>.Fail("Bankaya verme işlemi için banka hesabı seçilmelidir.","ACCOUNT_TYPE")));if(type==null&&a.AccountType is not("Bank" or "Cash"))return(null,Conflict(ApiResponse<object>.Fail("Çek tahsilatı için banka veya kasa hesabı seçilmelidir.","ACCOUNT_TYPE")));return(a,null);}
 async Task<CustomerCheque>New(ChequeRequest r,string status,CancellationToken ct){await db.Database.ExecuteSqlRawAsync("SELECT pg_advisory_xact_lock(81312)",ct);var prefix=$"CHQ-{r.ReceivedDate:yyyyMMdd}-";var values=await db.CustomerCheques.Where(x=>x.PortfolioNumber.StartsWith(prefix)).Select(x=>x.PortfolioNumber).ToListAsync(ct);var next=values.Select(x=>int.TryParse(x[prefix.Length..],out var n)?n:0).DefaultIfEmpty().Max()+1;var x=new CustomerCheque{Id=Guid.NewGuid(),PortfolioNumber=$"{prefix}{next:0000}",Status=status};Apply(x,r);db.CustomerCheques.Add(x);return x;}static void Apply(CustomerCheque x,ChequeRequest r){x.ChequeNumber=r.ChequeNumber.Trim();x.CustomerId=r.CustomerId;x.CustomerCollectionId=r.CustomerCollectionId;x.BankName=r.BankName.Trim();x.BankBranch=r.BankBranch;x.AccountHolder=r.AccountHolder;x.DrawerName=r.DrawerName;x.ChequeDate=r.ChequeDate.ToUniversalTime();x.DueDate=r.DueDate.ToUniversalTime();x.Currency=r.Currency.ToUpper();x.Amount=r.Amount;x.ReceivedDate=r.ReceivedDate.ToUniversalTime();x.BankReference=r.BankReference;x.Notes=r.Notes;}
 async Task<string?>Validate(ChequeRequest r,CancellationToken ct){if(r.Amount<=0)return"Çek tutarı sıfırdan büyük olmalıdır.";if(r.DueDate==default)return"Çek vadesi zorunludur.";if(string.IsNullOrWhiteSpace(r.Currency))return"Para birimi zorunludur.";if(string.IsNullOrWhiteSpace(r.ChequeNumber)||string.IsNullOrWhiteSpace(r.BankName)||string.IsNullOrWhiteSpace(r.DrawerName))return"Çek bilgileri zorunludur.";if(!await db.Customers.AnyAsync(x=>x.Id==r.CustomerId,ct))return"Müşteri bulunamadı.";return null;}
 void Event(CustomerCheque x,string type,string? previous,string next,Guid? account,Guid? ft,ChequeActionRequest? r)=>db.ChequeEvents.Add(new ChequeEvent{Id=Guid.NewGuid(),CustomerChequeId=x.Id,EventType=type,EventDate=DateTime.UtcNow,PreviousStatus=previous,NewStatus=next,FinancialAccountId=account,FinancialTransactionId=ft,ReferenceNumber=r?.ReferenceNumber,Notes=r?.Notes,Reason=r?.Reason,Created=DateTime.UtcNow});
 async Task<FinancialTransaction>Finance(FinancialAccount account,CustomerCheque cheque,string direction,string type,string sourceType,Guid sourceId,ChequeActionRequest r,CancellationToken ct){await db.Database.ExecuteSqlRawAsync("SELECT pg_advisory_xact_lock(81311)",ct);var prefix=$"FTX-{DateTime.UtcNow:yyyyMMdd}-";var vals=await db.FinancialTransactions.Where(x=>x.TransactionNumber.StartsWith(prefix)).Select(x=>x.TransactionNumber).ToListAsync(ct);var next=vals.Select(x=>int.TryParse(x[prefix.Length..],out var n)?n:0).DefaultIfEmpty().Max()+1;var x=new FinancialTransaction{Id=Guid.NewGuid(),TransactionNumber=$"{prefix}{next:0000}",FinancialAccountId=account.Id,TransactionDate=DateTime.UtcNow,TransactionType=type,Direction=direction,SourceType=sourceType,SourceId=sourceId,CustomerId=cheque.CustomerId,CustomerCollectionId=cheque.CustomerCollectionId,ChequeId=cheque.Id,Currency=cheque.Currency,Amount=cheque.Amount,Description=r.Notes,ReferenceNumber=r.ReferenceNumber,Created=DateTime.UtcNow};db.FinancialTransactions.Add(x);return x;}
}
public record CustomerChequeListDto(Guid Id,string PortfolioNumber,string ChequeNumber,Guid CustomerId,string CustomerCode,string CustomerName,Guid? CustomerCollectionId,string BankName,string DrawerName,DateTime ReceivedDate,DateTime DueDate,string Currency,decimal Amount,string Status,Guid? FinancialAccountId,bool IsReversed);
public record ChequeEventDto(Guid Id,string EventType,DateTime EventDate,string? PreviousStatus,string NewStatus,Guid? FinancialAccountId,Guid? FinancialTransactionId,string? ReferenceNumber,string? Notes,string? Reason);
public record ChequeRequest(string ChequeNumber,Guid CustomerId,Guid? CustomerCollectionId,string BankName,string? BankBranch,string AccountHolder,string DrawerName,DateTime ChequeDate,DateTime DueDate,string Currency,decimal Amount,DateTime ReceivedDate,string? BankReference,string? Notes);
public record ChequeActionRequest(Guid? FinancialAccountId,string? ReferenceNumber,string? Notes,string? Reason);
